Here's the full implementation:

### XAML — `ItemsPage.xaml`

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             xmlns:models="clr-namespace:MyApp.Models"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="Auto,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" Padding="8,0">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   TextColor="Gray" FontSize="12" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel — `ItemsViewModel.cs`

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    public ItemsViewModel(IApiService api)
    {
        _api = api;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (SelectedItem is null) return;

        await Shell.Current.GoToAsync(
            $"detail?id={SelectedItem.Id}");

        // Reset so the same item can be re-selected later
        SelectedItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;   // Must set false to hide spinner
        }
    }
}
```

### Key binding points

| XAML property | ViewModel member | Why |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item> Items` | Auto-updates UI on add/remove |
| `SelectedItem` (TwoWay) | `Item? SelectedItem` | VM reads the selection & resets it to `null` |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires navigation via `GoToAsync` |
| `RefreshView.Command` | `RefreshCommand` | Triggers API reload |
| `RefreshView.IsRefreshing` | `bool IsRefreshing` | Set `false` when done to hide the spinner |

### Important details

- **`x:DataType`** is set on both the page (ViewModel) and the DataTemplate (Model) for compiled bindings.
- **Reset `SelectedItem = null`** after navigating so the user can tap the same item again.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always hides, even on errors.
- Use **`ObservableCollection<T>`**, not `List<T>` — swapping a `List` forces a full re-render.
- Register the detail route in `AppShell.xaml.cs`:
  ```csharp
  Routing.RegisterRoute("detail", typeof(DetailPage));
  ```
